331	      return getComputedStyle(el).getPropertyValue(prop);
332	    },
333	    selector,
334	    index,
335	    prop,
336	  );
337	}
338	
339	/**
340	 * Computed style property of the Nth (0-indexed) element matching
341	 * `selector`'s `::after` pseudo-element — the widget-atom equivalent of
342	 * getLinePseudoComputedStyle, for guide-line assertions on table/callout/
343	 * html/hr (which don't render as a plain `.cm-line`, `.hr` excepted).
344	 */
345	export function getContentChildPseudoComputedStyle(
346	  selector: string,
347	  index: number,
348	  prop: string,
349	): Promise<string> {
350	  return browser.executeObsidian(
351	    ({ app, obsidian }, selector, index, prop) => {
352	      const view = app.workspace.getActiveViewOfType(obsidian.MarkdownView);
353	      if (!view) throw new Error('no active markdown view');
354	      const cm = (view.editor as any).cm;
355	      const matches = cm.contentDOM.querySelectorAll(selector);
356	      const el = matches[index] as HTMLElement | undefined;
357	      if (!el) throw new Error(`no "${selector}" at index ${index}`);
358	      return getComputedStyle(el, '::after').getPropertyValue(prop);
359	    },
360	    selector,
361	    index,
362	    prop,
363	  );
364	}
365	
366	/**
367	 * getBoundingClientRect() of the Nth (0-indexed) element anywhere under the
368	 * editor's content root — for comparing visual box positions across
369	 * elements that don't share a common line-index scheme (e.g. a widget's
370	 * nested visible content vs. a sibling `.cm-line`'s own box).
371	 */
372	export function getContentChildRect(selector: string, index: number): Promise<Rect> {
373	  return browser.executeObsidian(
374	    ({ app, obsidian }, selector, index) => {
375	      const view = app.workspace.getActiveViewOfType(obsidian.MarkdownView);
376	      if (!view) throw new Error('no active markdown view');
377	      const cm = (view.editor as any).cm;
378	      const matches = cm.contentDOM.querySelectorAll(selector);
379	      const el = matches[index] as HTMLElement | undefined;
380	      if (!el) throw new Error(`no "${selector}" at index ${index}`);
381	      const r = el.getBoundingClientRect();
382	      return { left: r.left, top: r.top, width: r.width, height: r.height };
383	    },
384	    selector,
385	    index,
386	  );
387	}
388	
389	export async function screenshotFull(dir: string, name: string): Promise<void> {
390	  await browser.saveScreenshot(path.join(dir, `${name}.png`));
391	}
392	
393	// ---- Notices --------------------------------------------------------------
394	
395	export async function noticeTexts(): Promise<string[]> {
396	  const notices = browser.$$('.notice');
397	  return notices.map((n) => n.getText());
398	}
399	
400	export async function waitForNotice(text: string): Promise<void> {
401	  await browser.waitUntil(
402	    async () => (await noticeTexts()).some((t) => t.includes(text)),
403	    { timeout: 4000, timeoutMsg: `notice containing "${text}" did not appear` },
404	  );
405	}
406	
407	/**
408	 * Poll the active editor's content DOM for a selector's match count, rather
409	 * than sleeping a fixed duration — a widget-replaced atom (table/callout/
410	 * html/hr) can settle its own DOM asynchronously after our decoration patch
411	 * runs, so a fixed pause is a race against however long that happens to take
412	 * (worse under system load). Waits until `expected` is observed, or throws.
413	 */
414	export async function waitForContentChildCount(
415	  selector: string,
416	  expected: number,
417	  timeout = 5000,
418	): Promise<void> {
419	  await browser.waitUntil(
420	    async () => {
421	      const count = await browser.executeObsidian(
422	        ({ app, obsidian }, selector) => {
423	          const view = app.workspace.getActiveViewOfType(obsidian.MarkdownView);
424	          if (!view) return -1;
425	          const cm = (view.editor as any).cm;
426	          return cm.contentDOM.querySelectorAll(selector).length as number;
427	        },
428	        selector,
429	      );
430	      return count === expected;
431	    },
432	    { timeout, timeoutMsg: `expected ${expected} "${selector}" element(s) within ${timeout}ms` },
433	  );
434	}
435	
436	export async function dismissNotices(): Promise<void> {
437	  await browser.execute(() => {
438	    document.querySelectorAll('.notice').forEach((n) => n.remove());
439	  });
440	}
441	
442	// ---- Keys -----------------------------------------------------------------
443	
444	const PRIMARY_MOD = process.platform === 'darwin' ? Key.Command : Key.Ctrl;
445	
446	export const keys = {
447	  tab: () => browser.keys(Key.Tab),
448	  shiftTab: () => browser.keys([Key.Shift, Key.Tab]),
449	  enter: () => browser.keys(Key.Enter),
450	  shiftEnter: () => browser.keys([Key.Shift, Key.Enter]),
451	  altUp: () => browser.keys([Key.Alt, Key.ArrowUp]),
452	  altDown: () => browser.keys([Key.Alt, Key.ArrowDown]),
453	  undo: () => browser.keys([PRIMARY_MOD, 'z']),
454	  type: (text: string) => browser.keys([...text]),
455	};
