1	/**
2	 * Outline-decorations Experiment 5a (per-kind block markers — icons, new
3	 * DOM-element mechanism) — see
4	 * docs/research/10-experiment-5-block-markers.md (Experiment 5's design and results).
5	 * Head-to-head alternative to Experiment 5b (CSS-shape markers, worked on a
6	 * sibling branch), NOT a fallback: screenshots every fixture in the shared
7	 * corpus (quote fixture included, promoted here), in both bundled themes,
8	 * plus targeted DOM/computed-style assertions — mirroring
9	 * 51-guides-gradient.e2e.ts's own discipline (read the browser's own
10	 * *resolved* values, not just the raw fact/class the code set, so a silent
11	 * cascade/clip override can't slip past unnoticed the way DOM-attribute-only
12	 * checks did in the original postmortem).
13	 *
14	 * Markers render via two mechanisms, split the same way indentation/guides
15	 * already are: a CM6 `Decoration.widget` for plain `.cm-line`s (heading/
16	 * paragraph/code/quote), and a direct DOM child injected by
17	 * `MarginCompensation` for widget-replaced atoms (table/callout/html/hr),
18	 * since a CM6 decoration has zero effect on those (confirmed by Experiment
19	 * 1/2b). List items are excluded entirely — native bullet/number only.
20	 */
21	
22	import * as fsp from 'node:fs/promises';
23	import * as path from 'node:path';
24	import { browser, expect } from '@wdio/globals';
25	import { obsidianPage } from 'wdio-obsidian-service';
26	import * as h from '../helpers.js';
27	import { ALL_DECORATION_FIXTURES } from '../fixtures/decorations.js';
28	
29	const SCREENSHOT_DIR = path.join(process.cwd(), '.obsidian-cache', 'block-markers-icons-screenshots');
30	const MARKER_ICON_SELECTOR = '.to-decor-marker-icon';
31	
32	async function ensureOutlineMode(notePath: string): Promise<void> {
33	  if (!(await h.isOutlineMode(notePath))) {
34	    await h.toggleOutlineMode();
35	    await h.waitForNotice('Outline mode on');
36	    await h.dismissNotices();
37	  }
38	}
