48	    await h.setTheme(false);
49	  });
50	
51	  afterEach(async function () {
52	    await h.dismissNotices();
53	  });
54	
55	  it('screenshots every fixture with outline mode on, light and dark', async function () {
56	    for (const fixture of ALL_DECORATION_FIXTURES) {
57	      await h.createNote(fixture.note, fixture.md);
58	      await ensureOutlineMode(fixture.note);
59	      await browser.pause(150);
60	
61	      await h.setTheme(false);
62	      await browser.pause(150);
63	      await h.screenshotFull(SCREENSHOT_DIR, `${fixture.label}-light`);
